(window.webpackJsonp=window.webpackJsonp||[]).push([[73],{700:function(n,i){n.exports='\x3c!-- \ntitle: 10-Esp8266入门\nsort: \n--\x3e \n# Esp8266入门\n\n## 配置\n\n> 安装驱动：CH340\n>\n> 开发板管理器网址：http://arduino.esp8266.com/stable/package_esp8266com_index.json\n>\n> 开发板：`NodeMCU 1.0 (ESP-12E Module)`\n\n## 第一个程序\n\n```c\n// AP模式\n#include <ESP8266WiFi.h>\n\nconst char *ssid = "fzf-esp8266";\n\nconst char *password = "8266isbest";\n\nvoid setup()\n{\n    Serial.begin(9600); // 串口通信\n    // 热点\n    WiFi.softAP(ssid, password);\n    // 连接wifi\n    // WiFi.begin(ssid,password)\n    // 判断是否连接\n    // WiFi.ststus() == WL_CONNECTED\n    /*\n    # 添加Wifi信息\n    ESP8266WiFiMulti wifiMulti;     \n    # 建立ESP8266WiFiMulti对象\n \n    wifiMulti.addAP(ssid1,passwd1);\n    wifiMulti.addAP(ssid2,passwd2);\n\t# 自动连接\n    wifiMulti.run()；\n    */\n\n    Serial.print("Access Point: ");\n    Serial.println(ssid);\n    Serial.print("IP: ");\n    Serial.println(WiFi.softAPIP());\n    // WiFi.localIP()\t# 连接WiFi后，本地地址。\n    // WiFi.SSID()\t\t# 连接WiFi后，WiFi名称。\n}\n\nvoid loop()\n{\n}\n\n```\n\n## 总结\n\n```c\n// 连接wifi\nWiFi.begin(ssid,password)\n// 根据添加的信息自动连接\nwifiMulti.addAP(ssid1,passwd1);\nwifiMulti.run();\t\n// 判断是否连接\nWiFi.ststus() == WL_CONNECTED;\n// 连接信息\nWiFi.localIP();\nWiFi.SSID();\n    \n// AP模式\niFi.softAP(ssid, password);\nWiFi.softAPIP();\n```\n\n\n\n'}}]);